module top_module(
  input            clk_dst,      
  input            rst_dst,      
  input            signal_src,   
  output reg       signal_dst    
);reg           meta_sync;     









  always @(posedge clk_dst)
  begin
    if (rst_dst)
    begin
      meta_sync <= 1'b0;
      signal_dst  <= 1'b0;
    end
    else 
    begin
      meta_sync <= signal_src;
      signal_dst  <= meta_sync;
    end 
  end 

endmodule
